root.js-content:
stp.writeLog("Start Add Amend PO");
stp.setAutoProcess(true);
stp.setUserId("CSBANK");
var sMainRef = stp.getSimpleRef("17");
stp.writeLog("sMainRef====="+sMainRef);
stp.setMainRef(sMainRef);
var sTxId = stp.getXslMsgTagVal("Document/BaselnAmdmntReq/TxId","Id");
stp.updateFieldValue("PARENT_MAIN_REF",sTxId);
var arrKeys = [["TSU_TID",sTxId]];
stp.writeLog("sTxId==========="+sTxId);
var arrGetDataResult = stp.SYS_getCUBKVal("GetMainRefByTxId",arrKeys);
var sTrxRole = arrGetDataResult[1];
stp.writeLog("sTrxRole==========="+sTrxRole);
stp.updateFieldValue("TSU_TRX_ROLE",sTrxRole);
stp.updateFieldValue("CURRNT_STATUS","Uploaded Amendment Purchase Order");
stp.updateFieldValue("NXT_STATUS","Waiting for Delta Report");
stp.writeLog("End Add Amend PO");
